        Customer a = new Customer("A", 20, "Tokyo");
        System.out.println(a.name());
        System.out.println(a.toString());
        System.out.println(a.hashCode());

        Customer b = new Customer("B", 20, "Osaka");
        System.out.println(a.equals(b));
